 *         return StorageSlot.getAddressSlot(_IMPLEMENTATION_SLOT).value;
 *     }
 *
 *     function _setImplementation(address newImplementation) internal {
 *         require(newImplementation.code.length > 0);
 *         StorageSlot.getAddressSlot(_IMPLEMENTATION_SLOT).value = newImplementation;
 *     }
 * }
 * ```
 *
 * TIP: Consider using this library along with {SlotDerivation}.
 */
library StorageSlot {
    struct AddressSlot {
        address value;
    }

    struct BooleanSlot {
        bool value;
    }

    struct Bytes32Slot {
        bytes32 value;
    }

    struct Uint256Slot {
        uint256 value;
    }

    struct Int256Slot {
        int256 value;
    }

    struct StringSlot {
        string value;
    }

    struct BytesSlot {
        bytes value;
    }

    /**
     * @dev Returns an `AddressSlot` with member `value` located at `slot`.
     */
    function getAddressSlot(bytes32 slot) internal pure returns (AddressSlot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `BooleanSlot` with member `value` located at `slot`.
     */
    function getBooleanSlot(bytes32 slot) internal pure returns (BooleanSlot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `Bytes32Slot` with member `value` located at `slot`.
     */
    function getBytes32Slot(bytes32 slot) internal pure returns (Bytes32Slot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `Uint256Slot` with member `value` located at `slot`.
     */
    function getUint256Slot(bytes32 slot) internal pure returns (Uint256Slot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `Int256Slot` with member `value` located at `slot`.
     */
    function getInt256Slot(bytes32 slot) internal pure returns (Int256Slot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns a `StringSlot` with member `value` located at `slot`.
     */
    function getStringSlot(bytes32 slot) internal pure returns (StringSlot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns an `StringSlot` representation of the string storage pointer `store`.
     */
    function getStringSlot(string storage store) internal pure returns (StringSlot storage r) {
        assembly ("memory-safe") {
            r.slot := store.slot
        }
    }

    /**
     * @dev Returns a `BytesSlot` with member `value` located at `slot`.
     */
    function getBytesSlot(bytes32 slot) internal pure returns (BytesSlot storage r) {
        assembly ("memory-safe") {
            r.slot := slot
        }
    }

    /**
     * @dev Returns an `BytesSlot` representation of the bytes storage pointer `store`.
     */
    function getBytesSlot(bytes storage store) internal pure returns (BytesSlot storage r) {
        assembly ("memory-safe") {
            r.slot := store.slot
        }
    }
}

contracts/interfaces/IPQCSignature.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title IPQCSignature
 * @notice Interface for Post-Quantum Cryptography signature verification
 * @dev Supports NIST standardized algorithms: Dilithium (ML-DSA) and Falcon
 */
interface IPQCSignature {

    enum PQAlgorithm {
        Dilithium2,    // NIST Level 2 (128-bit security)
        Dilithium3,    // NIST Level 3 (192-bit security)
        Dilithium5,    // NIST Level 5 (256-bit security)
        Falcon512,     // Fast signatures, smaller size
        Falcon1024     // Higher security level
    }

    struct SignatureInfo {
        bytes signature;
        bytes publicKey;
        PQAlgorithm algorithm;
        bytes32 qnrgSeedHash;      // Quantum entropy source
        bool quantumCertified;      // True if QNRG was used
    }

    /**
     * @notice Verify a PQC signature
     * @param message Hash of the message that was signed
     * @param signature PQC signature bytes
     * @param signer Address of the signer (for HSM lookup)
     * @return valid True if signature is valid
     */
    function verifyPQC(
        bytes32 message,
        bytes calldata signature,
        address signer
    ) external view returns (bool valid);

    /**
     * @notice Verify with explicit public key (for cross-chain proofs)
     * @param message Hash of the message
     * @param signature PQC signature
     * @param publicKey Signer's public key
     * @param algorithm Which PQC algorithm
     * @return valid True if signature is valid
     */
    function verifyPQCWithKey(
        bytes32 message,
        bytes calldata signature,
        bytes calldata publicKey,
        PQAlgorithm algorithm
    ) external pure returns (bool valid);

    /**
     * @notice Get the public key hash for a validator
     * @param validator Validator address
     * @return publicKeyHash Hash of the PQC public key
     * @return algorithm Algorithm used
     */
    function getValidatorKey(
        address validator
    ) external view returns (bytes32 publicKeyHash, PQAlgorithm algorithm);

    /**
     * @notice Check if validator has quantum-certified keys
     * @param validator Validator address
     * @return certified True if keys were generated with QNRG
     */
    function isQuantumCertified(address validator) external view returns (bool certified);
}

contracts/interfaces/IQuantumValidator.s.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title IQuantumValidator
 * @notice Interface for quantum validator coordination and QKD verification
 * @dev Manages QKD session establishment and Bell test verification
 */
interface IQuantumValidator {

    struct QKDSession {
        bytes32 sessionKeyHash;
        uint256 startTime;
        uint256 expiryTime;
        address alice;           // Validator node A
        address bob;             // Validator node B
        uint8 tier;              // 1=same-chip, 2=metro, 3=network
        bytes32 chshViolation;   // Bell test result hash
        bool active;
    }

    struct CHSHProof {
        uint256 S;               // CHSH parameter (should be > 2 for quantum)
        uint256[] outcomesA;     // Measurement outcomes from Alice
        uint256[] outcomesB;     // Measurement outcomes from Bob
        bytes32 basisChoicesA;   // Alice's basis choices hash
        bytes32 basisChoicesB;   // Bob's basis choices hash
        uint256 qber;            // Quantum Bit Error Rate (should be < 11%)
    }

    /**
     * @notice Verify a QKD proof (CHSH Bell test)
     * @param proof Encoded CHSH proof data
     * @param validator Validator claiming the QKD session
     * @return valid True if QKD is verified
     */
    function verifyQKDProof(
        bytes calldata proof,
        address validator
    ) external view returns (bool valid);

    /**
     * @notice Get active QKD session for a validator pair
     * @param alice Validator A
     * @param bob Validator B
     * @return session Session info
     */
    function getActiveSession(
        address alice,
        address bob
    ) external view returns (QKDSession memory session);

    /**
     * @notice Check if validator has active QKD with any peer
     * @param validator Validator to check
     * @return hasActive True if has active QKD session
     * @return sessionKeyHash Hash of the active session key
     */
    function hasActiveQKD(address validator) external view returns (
        bool hasActive,
        bytes32 sessionKeyHash
    );

    /**
     * @notice Get the QKD tier capability for a validator
     * @param validator Validator address
     * @return tier 1=same-chip, 2=metro, 3=network
     */
    function getQKDTier(address validator) external view returns (uint8 tier);

    /**
     * @notice Verify CHSH violation proof
     * @param chshProof CHSH proof structure
     * @return valid True if S > 2 (quantum correlation)
     * @return confidence Confidence level (0-10000)
     */
    function verifyCHSHViolation(
        CHSHProof calldata chshProof
    ) external pure returns (bool valid, uint256 confidence);
}

contracts/PQCSignatureVerifier.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./interfaces/IPQCSignature.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title PQCSignatureVerifier
 * @notice Implementation of PQC signature verification
 * @dev In production, this interfaces with HSM for actual PQC verification
 * For now, uses mock verification (real verification happens off-chain in Python backend)
 */
contract PQCSignatureVerifier is IPQCSignature, Ownable {

    // Validator => PQC Public Key info
    struct ValidatorKey {
        bytes publicKey;
        PQAlgorithm algorithm;
        bytes32 qnrgSeedHash;
        bool quantumCertified;
        bool registered;
    }

    mapping(address => ValidatorKey) public validatorKeys;
    mapping(bytes32 => bool) public usedSignatures; // Prevent replay

    // Events
    event ValidatorKeyRegistered(
        address indexed validator,
        bytes32 publicKeyHash,
        PQAlgorithm algorithm,
        bool quantumCertified
    );

    event SignatureVerified(
        bytes32 indexed messageHash,
        address indexed validator,
        bool valid
    );

    // ============ Constructor ============

    constructor() Ownable(msg.sender) {}

    // ============ External Functions ============

    /**
     * @notice Register a validator's PQC public key
     * @param publicKey The PQC public key bytes
     * @param algorithm Which PQC algorithm
     * @param qnrgSeedHash Hash of QNRG seed used for keygen
     * @param quantumCertified True if key was generated with quantum entropy
     */
    function registerValidatorKey(
        bytes calldata publicKey,
        PQAlgorithm algorithm,
        bytes32 qnrgSeedHash,
        bool quantumCertified
    ) external {
        require(!validatorKeys[msg.sender].registered, "Key already registered");
        require(publicKey.length > 0, "Invalid public key");

        validatorKeys[msg.sender] = ValidatorKey({
            publicKey: publicKey,
            algorithm: algorithm,
            qnrgSeedHash: qnrgSeedHash,
            quantumCertified: quantumCertified,
            registered: true
        });

        emit ValidatorKeyRegistered(
            msg.sender,
            keccak256(publicKey),
            algorithm,
            quantumCertified
        );
    }

    /**
     * @notice Verify PQC signature (looks up validator's registered key)
     */
    function verifyPQC(
        bytes32 message,
        bytes calldata signature,
        address signer
    ) external view returns (bool valid) {
        ValidatorKey memory key = validatorKeys[signer];
        require(key.registered, "Validator key not registered");

        // Check signature not replayed
        bytes32 sigHash = keccak256(signature);
        if (usedSignatures[sigHash]) {
            return false;
        }

        // In production: Call to HSM or precompile for actual PQC verification
        // For now: Mock verification that checks signature length and format
        valid = _mockVerifyPQC(message, signature, key.publicKey, key.algorithm);

        return valid;
    }

    /**
     * @notice Verify PQC with explicit key (for cross-chain validation)
     */
    function verifyPQCWithKey(
        bytes32 message,
        bytes calldata signature,
        bytes calldata publicKey,
        PQAlgorithm algorithm
    ) external pure returns (bool valid) {
        return _mockVerifyPQC(message, signature, publicKey, algorithm);
    }

    /**
     * @notice Get validator's public key info
     */
    function getValidatorKey(
        address validator
    ) external view returns (bytes32 publicKeyHash, PQAlgorithm algorithm) {
        ValidatorKey memory key = validatorKeys[validator];
        require(key.registered, "Validator not registered");
        return (keccak256(key.publicKey), key.algorithm);
    }

    /**
     * @notice Check if validator has quantum-certified keys
     */
    function isQuantumCertified(address validator) external view returns (bool certified) {
        return validatorKeys[validator].quantumCertified;
    }

    /**
     * @notice Mark signature as used (called by QLinkBridge after successful verification)
     * @param signature The signature to mark
     */
    function markSignatureUsed(bytes calldata signature) external {
        bytes32 sigHash = keccak256(signature);
        usedSignatures[sigHash] = true;
    }

    // ============ Internal Functions ============

    /**
     * @dev Mock PQC verification - validates signature format
     * In production, this calls HSM or uses EVM precompile for Dilithium/Falcon
     */
    function _mockVerifyPQC(
        bytes32 message,
        bytes calldata signature,
        bytes memory publicKey,
        PQAlgorithm algorithm
    ) internal pure returns (bool) {
        // Expected signature sizes based on algorithm
        uint256 expectedSigSize;
        uint256 expectedKeySize;

        if (algorithm == PQAlgorithm.Dilithium2) {
            expectedSigSize = 2420;
            expectedKeySize = 1312;
        } else if (algorithm == PQAlgorithm.Dilithium3) {
            expectedSigSize = 3293;
            expectedKeySize = 1952;
        } else if (algorithm == PQAlgorithm.Dilithium5) {
            expectedSigSize = 4595;
            expectedKeySize = 2592;
        } else if (algorithm == PQAlgorithm.Falcon512) {
            expectedSigSize = 666;
            expectedKeySize = 897;
        } else if (algorithm == PQAlgorithm.Falcon1024) {
            expectedSigSize = 1280;
            expectedKeySize = 1793;
        } else {
            return false;
        }

        // Basic length checks (real verification happens off-chain in Python)
        if (signature.length != expectedSigSize) return false;
        if (publicKey.length != expectedKeySize) return false;

        // Verify message hash format
        if (message == bytes32(0)) return false;

        // In production: Actual PQC verification would happen here
        // Return true for mock (real validation in Python backend)
        return true;
    }
}

contracts/QLinkBridge.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "./interfaces/IQuantumValidator.sol";
import "./interfaces/IPQCSignature.sol";

/**
 * @title QLinkBridge
 * @notice Quantum-safe cross-chain bridge with QKD + PQC
 * @dev Based on QLink paper: Quantum-Safe Bridge Architecture for Blockchain Interoperability
 * 
 * Architecture:
 * - Lock-and-mint mechanism for cross-chain transfers
 * - PQC signatures (Dilithium/Falcon) for validator proofs
 * - QKD-derived session keys for validator communication
 * - HSM-backed key custody for validators
 */
contract QLinkBridge is ReentrancyGuard, Ownable {
    using SafeERC20 for IERC20;

    // ============ Structs ============

    struct TransferRequest {
        bytes32 transferId;
        address sourceToken;
        address destToken;
        uint256 amount;
        address sender;
        address recipient;
        uint256 sourceChainId;
        uint256 destChainId;
        uint256 timestamp;
        bool executed;
    }

    struct ValidatorProof {
        bytes32 transferId;
        bytes pqcSignature;      // Dilithium or Falcon signature
        bytes32 qkdSessionKey;   // QKD-derived session key hash
        uint256 validatorId;
        uint256 timestamp;
    }

    struct QuantumSignature {
        bytes signature;
        uint8 algorithm;         // 1 = Dilithium2, 2 = Dilithium3, 3 = Dilithium5, 4 = Falcon
        bytes32 qnrgSeedHash;    // Hash of QNRG seed used
        bool quantumCertified;
    }

    // ============ State Variables ============

    // Transfer ID => TransferRequest
    mapping(bytes32 => TransferRequest) public transfers;

    // Transfer ID => Validator ID => Proof
    mapping(bytes32 => mapping(uint256 => ValidatorProof)) public proofs;

    // Transfer ID => proof count
    mapping(bytes32 => uint256) public proofCount;

    // Chain ID => supported (true/false)
    mapping(uint256 => bool) public supportedChains;

    // Token => supported (true/false)
    mapping(address => bool) public supportedTokens;

    // Validator ID => Validator info
    mapping(uint256 => address) public validators;
    mapping(address => bool) public isValidator;

    // QKD session key => expiry timestamp
    mapping(bytes32 => uint256) public qkdSessionExpiry;

    // PQC Signature verifier contract
    IPQCSignature public pqcVerifier;

    // Quantum validator coordinator
    IQuantumValidator public quantumValidator;

    uint256 public constant MIN_VALIDATORS = 3;
    uint256 public constant PROOF_THRESHOLD = 2; // Multi-sig threshold
    uint256 public constant QKD_SESSION_DURATION = 1 hours;
    uint256 public validatorCount;

    // ============ Events ============

    event TransferInitiated(
        bytes32 indexed transferId,
        address indexed sender,
        address indexed recipient,
        address token,
        uint256 amount,
        uint256 sourceChainId,
        uint256 destChainId
    );

    event ProofSubmitted(
        bytes32 indexed transferId,
        uint256 indexed validatorId,
        bytes32 qkdSessionKey,
        uint256 timestamp
    );

    event TransferExecuted(
        bytes32 indexed transferId,
        address indexed recipient,
        uint256 amount,
        uint256 proofCount
    );

    event ValidatorAdded(uint256 indexed validatorId, address validator);
    event ValidatorRemoved(uint256 indexed validatorId, address validator);
    event ChainSupported(uint256 indexed chainId);
    event ChainUnsupported(uint256 indexed chainId);

    // ============ Errors ============

    error InvalidTransfer();
    error ChainNotSupported(uint256 chainId);
    error TokenNotSupported(address token);
    error InsufficientProofs(bytes32 transferId);
    error InvalidPQCProof(bytes32 transferId, uint256 validatorId);
    error ExpiredQKDSession(bytes32 sessionKey);
    error TransferAlreadyExecuted(bytes32 transferId);
    error ValidatorNotAuthorized(address validator);
    error ProofAlreadySubmitted(bytes32 transferId, uint256 validatorId);

    // ============ Modifiers ============

    modifier onlyValidator() {
        if (!isValidator[msg.sender]) {
            revert ValidatorNotAuthorized(msg.sender);
        }
        _;
    }

    modifier validChain(uint256 chainId) {
        if (!supportedChains[chainId]) {
            revert ChainNotSupported(chainId);
        }
        _;
    }

    modifier validToken(address token) {
        if (!supportedTokens[token]) {
            revert TokenNotSupported(token);
        }
        _;
    }

    // ============ Constructor ============

    constructor(address _pqcVerifier, address _quantumValidator) Ownable(msg.sender) ReentrancyGuard() {
        pqcVerifier = IPQCSignature(_pqcVerifier);
        quantumValidator = IQuantumValidator(_quantumValidator);
    }

    // ============ External Functions ============

    /**
     * @notice Initiate a cross-chain transfer
     * @param token Token to transfer
     * @param amount Amount to transfer
     * @param recipient Destination address
     * @param destChainId Destination chain ID
     * @return transferId Unique identifier for this transfer
     */
    function initiateTransfer(
        address token,
        uint256 amount,
        address recipient,
        uint256 destChainId
    ) external nonReentrant validToken(token) validChain(destChainId) returns (bytes32) {
        if (amount == 0 || recipient == address(0)) {
            revert InvalidTransfer();
        }

        // Generate transfer ID using quantum entropy
        bytes32 transferId = keccak256(abi.encodePacked(
            msg.sender,
            token,
            amount,
            recipient,
            destChainId,
            block.timestamp,
            block.prevrandao // Use PoS randomness
        ));

        // Lock tokens
        IERC20(token).safeTransferFrom(msg.sender, address(this), amount);

        // Record transfer
        transfers[transferId] = TransferRequest({
            transferId: transferId,
            sourceToken: token,
            destToken: address(0), // Will be set by validator
            amount: amount,
            sender: msg.sender,
            recipient: recipient,
            sourceChainId: block.chainid,
            destChainId: destChainId,
            timestamp: block.timestamp,
            executed: false
        });

        emit TransferInitiated(
            transferId,
            msg.sender,
            recipient,
            token,
            amount,
            block.chainid,
            destChainId
        );

        return transferId;
    }

    /**
     * @notice Submit validator proof with PQC signature
     * @param transferId Transfer to prove
     * @param pqcSignature Dilithium/Falcon signature
     * @param qkdSessionKey QKD-derived session key hash
     */
    function submitProof(
        bytes32 transferId,
        bytes calldata pqcSignature,
        bytes32 qkdSessionKey
    ) external onlyValidator nonReentrant {
        TransferRequest storage transfer = transfers[transferId];

        if (transfer.executed) {
            revert TransferAlreadyExecuted(transferId);
        }

        // Verify QKD session is valid
        if (block.timestamp > qkdSessionExpiry[qkdSessionKey]) {
            revert ExpiredQKDSession(qkdSessionKey);
        }

        // Get validator ID
        uint256 validatorId = getValidatorId(msg.sender);

        // Check proof not already submitted
        if (proofs[transferId][validatorId].timestamp != 0) {
            revert ProofAlreadySubmitted(transferId, validatorId);
        }

        // Verify PQC signature
        bytes32 message = keccak256(abi.encodePacked(transferId, qkdSessionKey));
        if (!pqcVerifier.verifyPQC(message, pqcSignature, msg.sender)) {
            revert InvalidPQCProof(transferId, validatorId);
        }

        // Store proof
        proofs[transferId][validatorId] = ValidatorProof({
            transferId: transferId,
            pqcSignature: pqcSignature,
            qkdSessionKey: qkdSessionKey,
            validatorId: validatorId,
            timestamp: block.timestamp
        });

        proofCount[transferId]++;

        emit ProofSubmitted(transferId, validatorId, qkdSessionKey, block.timestamp);
    }

    /**
     * @notice Execute transfer after sufficient proofs
     * @param transferId Transfer to execute
     */
    function executeTransfer(bytes32 transferId) external nonReentrant {
        TransferRequest storage transfer = transfers[transferId];

        if (transfer.executed) {
            revert TransferAlreadyExecuted(transferId);
        }

        if (proofCount[transferId] < PROOF_THRESHOLD) {
            revert InsufficientProofs(transferId);
        }

        transfer.executed = true;

        // In production: mint wrapped tokens or release from liquidity pool
        // For now: emit event for off-chain handler
        emit TransferExecuted(
            transferId,
            transfer.recipient,
            transfer.amount,
            proofCount[transferId]
        );
    }

    /**
     * @notice Register a new QKD session key
     * @param sessionKeyHash Hash of QKD-derived session key
     * @param qkdProof Proof of QKD key establishment (CHSH violation data)
     */
    function registerQKDSession(
        bytes32 sessionKeyHash,
        bytes calldata qkdProof
    ) external onlyValidator {
        // Verify QKD proof via quantum validator contract
        if (!quantumValidator.verifyQKDProof(qkdProof, msg.sender)) {
            revert ExpiredQKDSession(sessionKeyHash);
        }

        qkdSessionExpiry[sessionKeyHash] = block.timestamp + QKD_SESSION_DURATION;
    }

    // ============ Admin Functions ============

    function addValidator(address validator) external onlyOwner {
        require(!isValidator[validator], "Already validator");

        validatorCount++;
        validators[validatorCount] = validator;
        isValidator[validator] = true;

        emit ValidatorAdded(validatorCount, validator);
    }

    function removeValidator(address validator) external onlyOwner {
        require(isValidator[validator], "Not validator");

        isValidator[validator] = false;
        validatorCount--;

        emit ValidatorRemoved(getValidatorId(validator), validator);
    }

    function supportChain(uint256 chainId) external onlyOwner {
        supportedChains[chainId] = true;
        emit ChainSupported(chainId);
    }

    function unsupportChain(uint256 chainId) external onlyOwner {
        supportedChains[chainId] = false;
        emit ChainUnsupported(chainId);
    }

    function supportToken(address token) external onlyOwner {
        supportedTokens[token] = true;
    }

    function setPQCVerifier(address _pqcVerifier) external onlyOwner {
        pqcVerifier = IPQCSignature(_pqcVerifier);
    }

    function setQuantumValidator(address _quantumValidator) external onlyOwner {
        quantumValidator = IQuantumValidator(_quantumValidator);
    }

    // ============ View Functions ============

    function getValidatorId(address validator) public view returns (uint256) {
        for (uint256 i = 1; i <= validatorCount; i++) {
            if (validators[i] == validator) {
                return i;
            }
        }
        return 0;
    }

    function getTransferStatus(bytes32 transferId) external view returns (
        bool exists,
        bool executed,
        uint256 proofs,
        uint256 required
    ) {
        TransferRequest storage t = transfers[transferId];
        return (
            t.timestamp != 0,
            t.executed,
            proofCount[transferId],
            PROOF_THRESHOLD
        );
    }

    function isQKDSessionValid(bytes32 sessionKey) external view returns (bool) {
        return block.timestamp <= qkdSessionExpiry[sessionKey];
    }
}

contracts/QuantumValidator.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./interfaces/IQuantumValidator.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title QuantumValidator
 * @notice Manages QKD sessions and validator coordination
 * @dev Interfaces with Python quantum backend for QKD proof verification
 */
contract QuantumValidator is IQuantumValidator, Ownable {

    // Validator => QKD sessions they participate in
    mapping(address => QKDSession[]) public validatorSessions;

    // Session key => session info
    mapping(bytes32 => QKDSession) public sessions;

    // Validator => current tier capability
    mapping(address => uint8) public validatorTiers;

    // Active session lookup: alice+bob => sessionKey
    mapping(bytes32 => bytes32) public activeSessionLookup;

    // Validators list
    address[] public validatorList;
    mapping(address => bool) public isRegisteredValidator;

    // QKD thresholds (from QLink paper)
    uint256 public constant CHSH_THRESHOLD = 20000; // S > 2.0 (scaled by 10000)
    uint256 public constant MAX_QBER = 1100;       // 11% QBER max (scaled by 10000)

    // Events
    event QKDSessionEstablished(
        bytes32 indexed sessionKeyHash,
        address indexed alice,
        address indexed bob,
        uint8 tier,
        uint256 chshS
    );

    event ValidatorRegistered(address indexed validator, uint8 tier);

    event CHSHVerified(
        bytes32 indexed sessionKeyHash,
        uint256 S,
        uint256 qber,
        bool valid
    );

    // ============ Constructor ============

    constructor() Ownable(msg.sender) {}

    // ============ External Functions ============

    /**
     * @notice Register a new validator with QKD tier capability
     * @param validator Validator address
     * @param tier QKD tier: 1=same-chip, 2=metro, 3=network
     */
    function registerValidator(address validator, uint8 tier) external onlyOwner {
        require(tier >= 1 && tier <= 3, "Invalid tier");
        require(!isRegisteredValidator[validator], "Already registered");

        validatorTiers[validator] = tier;
        isRegisteredValidator[validator] = true;
        validatorList.push(validator);

        emit ValidatorRegistered(validator, tier);
    }

    /**
     * @notice Establish QKD session between two validators
     * @param sessionKeyHash Hash of the QKD-derived session key
     * @param alice Validator A address
     * @param bob Validator B address
     * @param tier QKD tier used
     * @param chshProof Encoded CHSH proof
     */
    function establishQKDSession(
        bytes32 sessionKeyHash,
        address alice,
        address bob,
        uint8 tier,
        bytes calldata chshProof
    ) external {
        require(isRegisteredValidator[alice], "Alice not validator");
        require(isRegisteredValidator[bob], "Bob not validator");
        require(sessions[sessionKeyHash].startTime == 0, "Session exists");

        // Decode and verify CHSH proof
        (bool valid, uint256 S) = _verifyCHSHProof(chshProof);
        require(valid, "CHSH violation not proven");
        require(S > CHSH_THRESHOLD, "Insufficient CHSH violation");

        uint256 expiry = block.timestamp + 1 hours; // 1 hour session

        QKDSession memory session = QKDSession({
            sessionKeyHash: sessionKeyHash,
            startTime: block.timestamp,
            expiryTime: expiry,
            alice: alice,
            bob: bob,
            tier: tier,
            chshViolation: keccak256(chshProof),
            active: true
        });

        sessions[sessionKeyHash] = session;
        validatorSessions[alice].push(session);
        validatorSessions[bob].push(session);

        // Store lookup
        bytes32 lookupKey = keccak256(abi.encodePacked(alice, bob));
        activeSessionLookup[lookupKey] = sessionKeyHash;

        emit QKDSessionEstablished(sessionKeyHash, alice, bob, tier, S);
    }

    /**
     * @notice Verify QKD proof (called by QLinkBridge)
     */
    function verifyQKDProof(
        bytes calldata proof,
        address validator
    ) external view returns (bool valid) {
        // Decode proof: first 32 bytes = sessionKeyHash, rest = chshData
        require(proof.length >= 32, "Invalid proof format");

        bytes32 sessionKeyHash;
        assembly {
            sessionKeyHash := calldataload(add(proof.offset, 0))
        }

        QKDSession memory session = sessions[sessionKeyHash];

        // Check session is active and validator is participant
        if (!session.active) return false;
        if (session.expiryTime < block.timestamp) return false;
        if (session.alice != validator && session.bob != validator) return false;

        // CHSH already verified during establishment
        return true;
    }

    /**
     * @notice Get active session between two validators
     */
    function getActiveSession(
        address alice,
        address bob
    ) external view returns (QKDSession memory session) {
        bytes32 lookupKey = keccak256(abi.encodePacked(alice, bob));
        bytes32 sessionKey = activeSessionLookup[lookupKey];
        return sessions[sessionKey];
    }

    /**
     * @notice Check if validator has any active QKD session
     */
    function hasActiveQKD(address validator) external view returns (
        bool hasActive,
        bytes32 sessionKeyHash
    ) {
        QKDSession[] memory sessList = validatorSessions[validator];
        for (uint i = 0; i < sessList.length; i++) {
            if (sessList[i].active && sessList[i].expiryTime > block.timestamp) {
                return (true, sessList[i].sessionKeyHash);
            }
        }
        return (false, bytes32(0));
    }

    /**
     * @notice Get validator's QKD tier
     */
    function getQKDTier(address validator) external view returns (uint8 tier) {
        return validatorTiers[validator];
    }

    /**
     * @notice Verify CHSH violation parameters
     */
    function verifyCHSHViolation(
        CHSHProof calldata chshProof
    ) external pure returns (bool valid, uint256 confidence) {
        // S must be > 2 for quantum correlation
        if (chshProof.S <= CHSH_THRESHOLD) {
            return (false, 0);
        }

        // QBER must be < 11%
        if (chshProof.qber > MAX_QBER) {
            return (false, 0);
        }

        // Calculate confidence based on how far above threshold
        uint256 excess = chshProof.S - CHSH_THRESHOLD;
        confidence = excess * 10000 / CHSH_THRESHOLD;

        // Cap at 10000 (100%)
        if (confidence > 10000) confidence = 10000;

        return (true, confidence);
    }

    /**
     * @notice Close a QKD session (when compromised or expired)
     * @param sessionKeyHash Session to close
     */
    function closeQKDSession(bytes32 sessionKeyHash) external {
        QKDSession storage session = sessions[sessionKeyHash];
        require(
            msg.sender == session.alice || 
            msg.sender == session.bob || 
            msg.sender == owner(),
            "Not authorized"
        );

        session.active = false;
    }

    // ============ View Functions ============

    function getValidatorSessionCount(address validator) external view returns (uint256) {
        return validatorSessions[validator].length;
    }

    function getAllValidators() external view returns (address[] memory) {
        return validatorList;
    }

    function isSessionActive(bytes32 sessionKeyHash) external view returns (bool) {
        QKDSession memory s = sessions[sessionKeyHash];
        return s.active && s.expiryTime > block.timestamp;
    }

    // ============ Internal Functions ============

    /**
     * @dev Decode and verify CHSH proof data
     * @param proof Encoded CHSH proof
     * @return valid Whether proof is valid
     * @return S The CHSH parameter value
     */
    function _verifyCHSHProof(bytes calldata proof) internal pure returns (bool valid, uint256 S) {
        // Expected format: 
        // bytes 0-31: S (uint256)
        // bytes 32-63: QBER (uint256)
        // remaining: outcome data

        require(proof.length >= 64, "Proof too short");

        assembly {
            S := calldataload(add(proof.offset, 0))
            let qber := calldataload(add(proof.offset, 32))

            // Check QBER < 11%
            if gt(qber, 1100) {
                valid := 0
            }
            // Check S > 2 (scaled by 10000)
            if lt(S, 20001) {
                valid := 0
            }
            if iszero(or(lt(qber, 1100), lt(S, 20001))) {
                valid := 1
            }
        }

        return (valid, S);
    }
}

